const AWS = require('aws-sdk');
const crypto = require('crypto');

const dynamo = new AWS.DynamoDB.DocumentClient();

const TABLE_NAME = process.env.USERS_TABLE;
const EMAIL_GSI_NAME = process.env.EMAIL_GSI_NAME || 'email-index';
const PASSWORD_PEPPER = process.env.PASSWORD_PEPPER || '';
const PASSWORD_HASH_ITERATIONS = parseInt(process.env.PASSWORD_HASH_ITERATIONS || '210000', 10);
const PASSWORD_HASH_KEYLEN = parseInt(process.env.PASSWORD_HASH_KEYLEN || '32', 10);
const PASSWORD_HASH_DIGEST = process.env.PASSWORD_HASH_DIGEST || 'sha256';

function json(statusCode, body, headers = {}) {
  return {
    statusCode,
    headers: {
      'Content-Type': 'application/json',
      'Cache-Control': 'no-store',
      ...headers,
    },
    body: JSON.stringify(body),
  };
}

function normalizeEmail(email) {
  return String(email || '').trim().toLowerCase();
}

function isValidEmail(email) {
  if (!email || typeof email !== 'string') return false;
  const e = email.trim();
  if (e.length < 3 || e.length > 254) return false;
  const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return re.test(e);
}

function isValidPassword(password) {
  if (typeof password !== 'string') return false;
  const p = password;
  if (p.length < 8 || p.length > 128) return false;
  return true;
}

function base64url(buf) {
  return Buffer.from(buf)
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/g, '');
}

function nowIso() {
  return new Date().toISOString();
}

function pbkdf2Async(password, salt, iterations, keylen, digest) {
  return new Promise((resolve, reject) => {
    crypto.pbkdf2(password, salt, iterations, keylen, digest, (err, derivedKey) => {
      if (err) return reject(err);
      resolve(derivedKey);
    });
  });
}

async function hashPassword(password) {
  const salt = crypto.randomBytes(16);
  const derived = await pbkdf2Async(password + PASSWORD_PEPPER, salt, PASSWORD_HASH_ITERATIONS, PASSWORD_HASH_KEYLEN, PASSWORD_HASH_DIGEST);
  return {
    alg: 'pbkdf2',
    digest: PASSWORD_HASH_DIGEST,
    iterations: PASSWORD_HASH_ITERATIONS,
    salt: base64url(salt),
    hash: base64url(derived),
    keylen: PASSWORD_HASH_KEYLEN,
  };
}

function parseBody(event) {
  if (!event || event.body == null) return null;
  if (typeof event.body === 'object') return event.body;
  let raw = event.body;
  if (event.isBase64Encoded) {
    raw = Buffer.from(raw, 'base64').toString('utf8');
  }
  try {
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

async function emailExists(email) {
  const params = {
    TableName: TABLE_NAME,
    IndexName: EMAIL_GSI_NAME,
    KeyConditionExpression: '#email = :email',
    ExpressionAttributeNames: { '#email': 'email' },
    ExpressionAttributeValues: { ':email': email },
    Limit: 1,
  };
  const res = await dynamo.query(params).promise();
  return (res.Items && res.Items.length > 0);
}

exports.handler = async (event) => {
  try {
    if (!TABLE_NAME) return json(500, { message: 'Server misconfigured: USERS_TABLE not set' });

    const method = (event.httpMethod || event.requestContext?.http?.method || '').toUpperCase();
    if (method && method !== 'POST') return json(405, { message: 'Method Not Allowed' }, { Allow: 'POST' });

    const body = parseBody(event);
    if (!body) return json(400, { message: 'Invalid JSON body' });

    const email = normalizeEmail(body.email);
    const password = body.password;

    if (!isValidEmail(email)) return json(400, { message: 'Invalid email' });
    if (!isValidPassword(password)) return json(400, { message: 'Invalid password (min 8 chars)' });

    const exists = await emailExists(email);
    if (exists) return json(409, { message: 'Email already registered' });

    const userId = 'usr_' + base64url(crypto.randomBytes(16));
    const createdAt = nowIso();
    const passwordHash = await hashPassword(password);

    const item = {
      pk: `USER#${userId}`,
      sk: `USER#${userId}`,
      userId,
      email,
      createdAt,
      updatedAt: createdAt,
      passwordHash,
      status: 'ACTIVE',
      version: 1,
    };

    await dynamo
      .put({
        TableName: TABLE_NAME,
        Item: item,
        ConditionExpression: 'attribute_not_exists(pk)',
      })
      .promise();

    return json(201, { userId, email, createdAt });
  } catch (err) {
    const code = err && err.code;
    if (code === 'ConditionalCheckFailedException') {
      return json(409, { message: 'Account already exists' });
    }
    return json(500, { message: 'Internal Server Error' });
  }
};